+function parseCommandLine(value: string): string[] {
+  const args: string[] = []
+  let current = ''
+  let inQuotes = false
+  let escapeNext = false
+
+  for (const char of value) {
+    if (escapeNext) {
+      current += char
+      escapeNext = false
+      continue
+    }
+    if (char === '\\') {
+      escapeNext = true
+      continue
+    }
+    if (char === '"') {
+      inQuotes = !inQuotes
+      continue
+    }
+    if (!inQuotes && /\s/.test(char)) {
+      if (current) {
+        args.push(current)
+        current = ''
+      }
+      continue
+    }
+    current += char
+  }
+  if (current) args.push(current)
+  return args
+}
